class Solution {
public:
    vector<int> findSubstring(string s, vector<string>& words) {
        int n = s.length();
        vector<int> result(n, -1);

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < words.size(); j++) {
                int k = 0;
                for (int k = 0; k < words[j].length(); k++) {
                    if (s.substr(i, words[j].length()) == words[j] && result[i] == -1) {
                        result[i] = j;
                    }
                }
            }
        }
        return result;
    }
};
